// Fill in ROOT_FOLDER_ID before running.
const config = {
  ROOT_FOLDER_ID: 'YOUR_GOOGLE_DRIVE_ROOT_FOLDER_ID',
  TIMEZONE: 'Asia/Taipei'
};
if (!config.ROOT_FOLDER_ID || config.ROOT_FOLDER_ID.startsWith('YOUR_')) {
  throw new Error('請先在 Config 節點填入 ROOT_FOLDER_ID');
}
const ROOT_SUBFOLDERS = [
  '01_公文專案啟動表',
  '02_專案總控表',
  '03_專案資料夾',
  '04_專案階段日期新增表',
  '06_Apps Script'
];
const controlHeaders = ['專案編號','專案名稱','年度','承辦處室','承辦人','承辦人Email','Drive資料夾連結','專案紀錄Docs連結','待辦追蹤表連結','成果檢核表連結','NotebookLM筆記本連結','專案狀態','備註','來文單位','公文文號','建立日期','活動日期','成果期限','經費期限','是否有經費'];
const milestoneHeaders = ['紀錄編號','新增時間','建立者Email','專案編號','專案名稱','日期類型','日期','提醒設定','負責人','負責人Email','是否寫入待辦追蹤表','是否建立Calendar提醒','說明','Calendar事件ID','對應待辦追蹤表連結','狀態','備註'];
function headerRow(headers) { const o={}; for (const h of headers) o[h]=h; return o; }
return [{ json: { config, ROOT_SUBFOLDERS, controlHeaders, milestoneHeaders, controlHeaderRow: headerRow(controlHeaders), milestoneHeaderRow: headerRow(milestoneHeaders) } }];

const { config, ROOT_SUBFOLDERS } = $input.first().json;
const base = $input.first().json;
return ROOT_SUBFOLDERS.map(name => ({ json: { ...base, folderName: name } }));

// Merge results — each item is either an existing search hit or a freshly-created folder.
const all = $input.all();
const byName = {};
for (const it of all) {
  const j = it.json;
  if (j.name && j.id) byName[j.name] = j.id;
}
const config = $('Config').first().json.config;
const base = $('Config').first().json;
return [{ json: { ...base, rootSubfolderIds: byName, controlFolderId: byName['02_專案總控表'] } }];

const created = $input.first().json;
const base = $('Collect root folders').first().json;
return [{ json: { ...base, controlSheetId: created.spreadsheetId, controlSheetUrl: created.spreadsheetUrl || `https://docs.google.com/spreadsheets/d/${created.spreadsheetId}/edit` } }];

// Feed header row as data items so autoMapInputData writes a row with header names as values.
const prep = $('Carry control sheet id').first().json;
return [{ json: { ...prep, ...prep.controlHeaderRow } }];

// Build a batchUpdate body that needs the two sheets' internal numeric sheetIds.
// We need the actual sheetIds (Google internally assigns them). Fetch via Drive? No —
// use the Sheets API metadata: a separate GET would be cleaner; instead we encode by index.
// In the freshly-created spreadsheet, sheet 0 = 行政專案總控表, sheet 1 = 專案階段日期紀錄
// but Google sometimes assigns non-zero ids. Safer: refer by sheet *title*.
const prep = $('Carry control sheet id').first().json;
// We'll use a small lookup pass via Sheets metadata in the next node.
return [{ json: prep }];

const prep = $('Carry control sheet id').first().json;
const meta = $input.first().json;
const byTitle = {};
for (const s of (meta.sheets || [])) byTitle[s.properties.title] = s.properties.sheetId;
const controlSheetIdNum = byTitle['行政專案總控表'];
const milestoneSheetIdNum = byTitle['專案階段日期紀錄'];
function headerFormatRequests(sheetId, columnCount) {
  return [
    { repeatCell: { range: { sheetId, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: columnCount }, cell: { userEnteredFormat: { textFormat: { bold: true }, backgroundColor: { red: 0.92, green: 0.95, blue: 1 } } }, fields: 'userEnteredFormat(textFormat,backgroundColor)' } },
    { updateSheetProperties: { properties: { sheetId, gridProperties: { frozenRowCount: 1 } }, fields: 'gridProperties.frozenRowCount' } }
  ];
}
const body = { requests: [
  ...headerFormatRequests(controlSheetIdNum, prep.controlHeaders.length),
  ...headerFormatRequests(milestoneSheetIdNum, prep.milestoneHeaders.length)
]};
return [{ json: { ...prep, _formatBody: body } }];

const prep = $('Carry control sheet id').first().json;
return [{
  json: {
    ok: true,
    CONTROL_SHEET_ID: prep.controlSheetId,
    CONTROL_SHEET_URL: prep.controlSheetUrl,
    rootSubfolderIds: prep.rootSubfolderIds,
    nextSteps: [
      '1. 把上面的 CONTROL_SHEET_ID 填回 entry-* workflow 的 Config 節點。',
      '2. 之後送出公文專案啟動表會自動寫入這張總控表。',
      '3. 若使用 Google Forms 入口，記得把 apps-script-bridge.gs 部署到對應的 Form 試算表。'
    ]
  }
}];
